using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the old name so existing 500K documents remain readable and
            // direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|KeyValue" to just "KeyValue".
            // Preserve the old format so existing documents are still addressable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        base.OnConfiguring(optionsBuilder);
    }
}

// Generates ids in the legacy "Product|{key}" format used by EF Core 8.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{entry.Property("Id").CurrentValue}";
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

