using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed to "$type".
            // Preserve old name so 500K existing documents and direct SQL
            // queries (c.Discriminator) continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Resource-id format changed from "Product|123" to "123".
            // Override the __id shadow property value generator to keep the old format
            // so existing documents remain addressable.
            entity.Property<string>("__id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex() now throws (was silently ignored).
            // Removed: entity.HasIndex(p => p.Sku);
            // Cosmos DB indexes are managed via the container's indexing policy,
            // not through EF Core. Configure them in the Azure Portal or via IaC.
        });
    }
}

/// <summary>
/// Generates Cosmos resource-id values in the EF Core 8 format: "EntityType|KeyValue".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var typeName = entry.Metadata.ShortName();
        var keyValue = entry.Property("Id").CurrentValue;
        return $"{typeName}|{keyValue}";
    }
}

